var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"요즘 같은 시대에도 여전히 종이책 읽는 걸 좋아하는군, 비블리데.","JPN":"このような時代になっても、相変わらず紙の本の方を好むのだね、ビブリデ。","ENG":"I see you are still reading those paper books, Biblide.","TWN":"現在竟然還有人喜歡讀紙本書呢，布莉黛。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"하긴, 자네와 베네딕트는 어렸을 때부터 책을 참 좋아했지.","JPN":"まあ、君とベネディクトは小さい頃から本が大好きだったからな。","ENG":"Well, you and Benedict practically buried yourselves in books since you were children.","TWN":"也是，你和本尼迪克特從小就很喜歡看書。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"두 사람이 경쟁하듯, 고아원에 있던 책이란 책은 모조리 읽어서 곤란할 정도였어. 허허.","JPN":"二人が競争するように、孤児院にある本をすべて読んでしまったのには困ったものだ。ホッホッ。","ENG":"It was as if you two were trying to see who could read the most books, and in the end, I was the one in trouble because you both read every book there is at the orphanage. *Chuckle*","TWN":"二個人好像在比賽一樣，把孤兒院裡只要像書的東西全都翻出來看，真是令人傷腦筋呢，呵呵～"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"지금도 그 때만 생각하면…….","JPN":"今でもあの時のことを考えると……","ENG":"When I think back on those times─","TWN":"現在回想起來……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해드리죠, 예하.","JPN":"喜んで訂正いたします、猊下。","ENG":"I would be more than happy to rephrase, your Eminence.","TWN":"我要更正一下，主教。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하께서 곤란하셨던 까닭은 벽장 속에 숨겨 두신 성인 잡지도 찾아내서 읽었기 때문으로 알고 있습니다만.","JPN":"猊下がお困りになった理由は、押し入れに隠されたアダルト雑誌をも見つけて読んでしまったためです。","ENG":"Your Eminence, the only reason you were in trouble was because I discovered, and read, the naughty magazine you had hidden in the closet.","TWN":"據我所知，主教之所以會傷腦筋，是因為藏在櫃子裡的成人雜誌被發現。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"흠, 크흠. 그 잡지는 내 것이 아니래도.","JPN":"ふむ、こほん。あの雑誌は私のものではないと言ったではないか。","ENG":"Hmm... Ahem! Did I not say that the magazine is not mine?","TWN":"咳咳，就說那本雜誌不是我的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그, 그래서 도서관을 담당하는 일은 할 만하고?","JPN":"そ、それで図書館の仕事の方はどうだね？","ENG":"A-anyway, how is your work as a librarian fairing?","TWN":"那個，在圖書館工作還習慣吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주님께서는 모든 어린 양들에게 재능을 부여하시고 그에 걸맞은 결실을 맺길 바라십니다.","JPN":"主はすべての子羊に才能を与え、それにふさわしい実りをお望みです。","ENG":"The Lord has given all of his lambs talents, and desires for them to bear fruit.","TWN":"天主有給每隻小羊才幹，並且期待能夠結果子。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그리고 저의 재능에 걸맞은 일은 얌전히 이 서고에서 후세에 전할 지식을 보존하는 것이겠죠.","JPN":"そして私の才能にふさわしい仕事とは、大人しくこの書庫で後世に伝える知識を保存することでしょう。","ENG":"With my talent, I intend to quietly preserve the knowledge that I will pass on to future generations in this library.","TWN":"而符合我才幹的工作，就是老實待在圖書館裡，替下一代保管好這些寶貴的知識。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"허허……. 나는 아직 아무 말도 안 했다만?","JPN":"ホッホッ……私はまだ何も言っていないが？","ENG":"*Chuckle* But I have not said anything yet?","TWN":"呵呵……我什麼都還沒說呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"천사는 가까이…… 하지만 사탄은 더 가까이……","JPN":"天使と親しく……だが悪魔にはもっと親しく……","ENG":"Keep angels close... but the devil closer...","TWN":"離天使近一點……離撒旦更近一點……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청 대침식전 전문 기관, 기적심의회. 세간에서 부르는 속칭은 <color=#ffd34c>주님의 미친개들</color>.\xA0","JPN":"聖皇庁の対侵食戦専門機関、奇跡審議会。世間での俗称は<color=#ffd34c>主の狂犬たち</color>。\xA0","ENG":"The Miracle Investigation Council, Holy Curia's Anti-Corruption Institution. Or, as some people call it, the <color=#ffd34c>Mad Dogs of the Lord</color>.\xA0","TWN":"聖皇廳侵蝕戰專責機關 奇蹟議會，世人俗稱為<color=#ffd34c>天主的走狗</color>。\xA0"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 의장이신 요한 추기경께서 이런 낡은 서고를 찾아주시니 몸 둘 바를 모르겠군요.","JPN":"その議長であるヨハン枢機卿猊下に、このような古い書庫をお訪ねいただき光栄です。","ENG":"It is an honor that you, Cardinal Johan, Chairman of Miracle Investigation Council, personally pays me a visit at this old library.","TWN":"議長約翰樞機主教突然大駕光臨，真是受寵若驚呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"크흠. 불경한 이단들이나 부르는 별명 아닌가. 섭섭하구만.","JPN":"こほん。それは不敬な異端者たちが呼ぶ名ではないか。寂しいことを言う。","ENG":"Ahem... Is that not what those profane heretics refer to us as? I am truly disappointed.","TWN":"咳咳，異端才會那麼稱呼不是嗎？真令人難過。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"우리 심의회도 대외적인 이미지 쇄신을 위해 노력 중이네.","JPN":"審議会も対外的なイメージ刷新のために努力しているんだ。","ENG":"Although, the Investigation Council is working hard to improve our public image.","TWN":"議會已經努力在洗刷外界對我們的刻板印象。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"자네가 없는 사이, 귀여운 후배들도 잔뜩 생겼지.","JPN":"君がいない間に、可愛い後輩たちもたくさん入ってきたんだぞ。","ENG":"Also, while you were away, a lot of cute junior members have joined.","TWN":"你不在的這段時間，議會裡也是可愛的新人輩出呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"특히 루퍼 양은 자네 어릴 때를 쏙 빼닮았어.\xA0","JPN":"特にルーパー君は君の小さい頃にそっくりだ。\xA0","ENG":"Miss Looper, in particular, reminds me of you as a child.\xA0","TWN":"尤其是洛珀，她和你小時候簡直是一個模子刻出來的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그만 용건을 말씀해 주시죠. 서문이 긴 책은 매력이 없는 법입니다.\xA0","JPN":"そろそろ用件をお話しください。序文が長い本は魅力がありません。\xA0","ENG":"Could you tell me the reason for your visit? A book with a lengthy introduction is unlikely to be appealing.\xA0","TWN":"請主教直接進入正題吧，前言太冗長的書沒什麼吸引力。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그럼 단도직입적으로 말하지. 성무 SI3E에 대한 조사를 부탁하고 싶네.","JPN":"それでは単刀直入に言おう。聖務SI3Eの調査を頼みたい｡","ENG":"I will say it outright. I want you to investigate Sacred Mission SI3E.","TWN":"那我就直說了，我想拜託你調查聖務SI3E一事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성무 SI3E라고 하시면……?","JPN":"聖務SI3Eとおっしゃいますと……?","ENG":"Sacred Mission SI3E...?","TWN":"聖務SI3E……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"최근 성무에 파견됐던 용병단이 행방불명됐다는 소문은 익히 들어 알고 있겠지?","JPN":"最近、聖務に派遣された傭兵団が行方不明になったという噂は聞いているだろう?","ENG":"Did you not hear about the deployed mercenaries going missing while on a sacred mission recently?","TWN":"你應該也有聽說，最近派去執行聖務的傭兵團下落不明一事吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그 성무를 맡았던 곳이 바로 제 9호 기적심의회였어.","JPN":"その聖務を担当していたのが第9号奇跡審議会だったのだ｡","ENG":"That sacred mission was overseen by the Miracle Investigation Council 9.","TWN":"而負責那個聖務的就是第9奇蹟議會。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제 9호라면…….","JPN":"第9号でしたら……","ENG":"Council 9 is...","TWN":"第9……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 남자가 담당하고 있는 심의회로군요.","JPN":"あの男が担当している審議会ですね。","ENG":"That's the Investigation Council \\"he\\" is in charge of, is it not?","TWN":"不是那男的在負責治理的嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그래. 원래 베네딕트가 올린 보고서대로라면 집행이 완료된 성무였지.","JPN":"そう。もともとベネディクトが提出した報告書どおりなら執行は完了しているはずの聖務だった。","ENG":"Yes. According to Benedict's report, the sacred mission was completed.","TWN":"沒錯，照本尼迪克特原本提交的報告來看，聖務應該是有達成的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"성무에 이바지하던 신자들을 잃은 건 애석한 일이지만, 문제될 건 없었어.","JPN":"聖務に貢献していた信者を失ったことは実に残念だが、問題になるようなものはなかった。","ENG":"Although it is a pity that many souls were lost during the mission, there were no problems.","TWN":"雖然有人因為聖務而犧牲，很令人惋惜，但這也是正常的。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그런데……. 보고서에는 기록되지 않았던 수상한 정황들이 계속 밝혀지더군.","JPN":"しかし……報告書には記録されていなかった怪しい状況が続々と明らかになってな。","ENG":"However... Strange circumstances that were not recorded in the report have come to light.","TWN":"只是……我們後來發現，有許多沒記錄在報告裡的可疑事項。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"유감스럽게도 베네딕트는 이 건에 대해 침묵으로 일관하고 있다네.","JPN":"残念ながらベネディクトはこの件について沈黙で押し通している。","ENG":"Unfortunately, Benedict remains silent on this matter.","TWN":"遺憾的是，本尼迪克特本人對於這件事一概三緘其口。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"조만간 내가 직접 심문할 텐데, 그 전에 이번 성무의 내막을 더 자세히 조사할 필요가 있어.","JPN":"そのうち私が直接審問する予定だが、その前に今度の聖務の内幕をもっと詳しく調査する必要があるのだ。","ENG":"I will go question him myself soon enough, but first I need someone to conduct a thorough investigation.","TWN":"很快我就會親自審問他，在那之前，有必要更仔細地調查事情的真相。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"이대로 뒀다가는 자칫 그 녀석이 전부 뒤집어쓸지도 모를 테니 말이다.","JPN":"このままでは、あの子がすべての罪をかぶることになりかねんからな。","ENG":"If we do not do anything, he might really take the fall for everything.","TWN":"我擔心這樣下去，那小子會一個人全扛下來。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……예하께서는 여전히 정이 많으시군요.","JPN":"……猊下は相変わらず多情でいらっしゃいますね。","ENG":"...I see you still care a lot about him, your Eminence.","TWN":"……主教還是一樣重感情呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오히려 그 정 때문에 외면해선 안 될 것을 외면하고 계시는 것 같아 우려스럽습니다.","JPN":"むしろその情のせいで、見て見ぬふりをなさるのではかいかと心配です。","ENG":"However, I am concerned that you may be ignoring issues that should not be ignored.","TWN":"但我擔心，主教會不會因為這樣，而忽略掉不該忽略的部分呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"무슨 말인가?","JPN":"どういう意味かね？","ENG":"I beg your pardon?","TWN":"什麼意思？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"도서관에서 일하다 보면 원치 않아도 읽게 되는 소문들이 있습니다.","JPN":"図書館で働いていると、望まずとも読んでしまう噂があります。","ENG":"Working at the library also means I get to read rumors, whether I want to or not.","TWN":"在圖書館做事，總是會出於非自願地讀到一些流言蜚語。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 그 자가 금서로 지정된 서적들을 탐독한다는 소문은 그를 잘 모르는 이들의 뜬소문일 뿐이죠.","JPN":"ですがあの人が禁書に指定された書籍を耽読しているという噂は、彼をよく知らない者たちの根も葉もない噂に過ぎません。","ENG":"On the other hand, rumors about \\"him\\" indulging in forbidden books must sound like wild rumors to those unacquainted with him.","TWN":"不過會謠傳他愛讀禁書的人，可能跟他不太熟，"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오히려 읽는 것에서 그치면 다행이라고 생각해야 할 겁니다.","JPN":"むしろ読むだけで終われば幸いというべきでしょう。","ENG":"However, I would consider it a blessing if \\"he\\" only reads and does not act.","TWN":"我個人認為，若只有讀而已那還算是萬幸。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"기적심의회의 적은 침식체를 숭배하는 자들도 포함되지. 적에 대해 아는 건 전술의 기본 아닌가.","JPN":"奇跡審議会の敵には侵食体の崇拝者も含まれる。敵について知っておくのは戦術の基本ではないか。","ENG":"Worshippers of C.O.s are among our enemies. Is it not common practice to study them?","TWN":"奇蹟議會的敵人也包括那些崇拜侵蝕體的人，知己知彼才能百戰百勝不是嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"누구보다 어린 양들을 아끼는 녀석이야.","JPN":"誰よりも子羊を大切に思っている子だ。","ENG":"He cares about the little ones more than anyone.","TWN":"他比誰都愛護小羊，"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그렇게 한 몸 바쳐 일선에서 헌신하는 사람을 나는 본 적 없네.","JPN":"私はあの子ほど献身的に一線で働く者を見たことがない。","ENG":"I have never seen anyone so devoted in the front line as him.","TWN":"我沒見過像他如此將自己奉獻在第一線的人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼 성무 중 회수한 금서를 반출하여 개인적으로 사용한 일도 기억 못하시겠군요.","JPN":"そうなると聖務中に回収した禁書を搬出し、個人的に使用したことも覚えていらっしゃらないでしょうね。","ENG":"Then you will probably not remember \\"him\\" taking the forbidden book that was recovered on a sacred mission and keeping it for his own personal use?","TWN":"看來主教似乎不記得，他是如何將聖務中回收的禁書挪為私用的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예전부터 그 남자에게는 이단에 빠진 징후가 보였죠. 부디 외면하지 마시길 바랍니다.","JPN":"昔からあの男には異端に傾倒する兆候が見えていました。どうか目を背けないでください。","ENG":"For a long time, \\"he\\" has displayed signs of heresy. I strongly advise you to not look past that.","TWN":"那男的從以前就手腳不乾淨，請主教不要刻意忽視。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"자네……. 여전히 그 일을 마음에 두고 있었군.","JPN":"君……まだあのことを気にしていたのだな。","ENG":"Biblide... I see you still have concerns about \\"that case\\".","TWN":"你……還是很介意那件事是嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"하지만 금서 건이나 그 사건이나, 이제는 다 지나간 일이야.","JPN":"だが禁書の件もあの件も、もう過ぎたことだ。","ENG":"Whether it be the forbidden book or that case, it's all in the past now.","TWN":"無論是禁書或是那件事，都已經是過去式。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"사제 서품을 받은 자가 이교도의 주술로 환자를 치료하려 했습니다.","JPN":"聖職を授任された者が異教徒の呪術で患者を治療しようとしました。","ENG":"An ordained priest tried to cure the sick with heresy magic.","TWN":"一個接受聖職的人，竟然想利用異端的邪術來治療病患。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"결코 시간이 해결해 줄 문제는 아니라고 생각합니다만. ","JPN":"決して時間が解決してくれる問題ではないと思いますが。 ","ENG":"I do not believe that this is an issue that can be resolved with the passing of time.","TWN":"這件事不是一句過去式就可以當作沒這回事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그 곳은 주님의 축복이 닿지 않는 곳이었어. 일단 사람을 살리는 게 먼저 아닌가.","JPN":"あの場所は主の祝福が届かないところだったのだ。人の命を救うことが最優先だった。","ENG":"Nonetheless, it was done in a place where the Lord's blessing does not reach. Also, saving human lives is our top priority, is it not?","TWN":"那是未受到天主祝福的地方，救人要緊不是嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"도와주게. 피는 섞이지 않았어도 자네와 베네딕트 모두 내 가족이나 다름없어.","JPN":"助けてやってくれ。血は繋がっていなくとも君とベネディクトは家族も同然だ。","ENG":"So will you help me? Though we are not related by blood, I still think both of you as family.","TWN":"你幫幫我吧，雖然我們沒有血緣關係，但你和本尼迪克特就像我的家人一樣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하께서 그 남자를 자식처럼 여기시는 것은 잘 알겠습니다만.","JPN":"猊下があの男を息子のように思っていらっしゃることはよくわかりますが。","ENG":"Your Eminence, I understand you care for \\"him\\" as if he was your own.","TWN":"我知道主教將那男的視如己出，"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"같은 시설에 거둬져, 같은 것을 먹고, 같은 것을 보고 배웠다고 하더라도…… 가족이 되는 건 아닐 겁니다.","JPN":"同じ施設に引き取られ、同じものを食べ、同じものを見て学んだとしても……家族になるわけではないはずです。","ENG":"However, simply because we were raised, fed, and grew up in the same facility... It does not make us \\"family\\".","TWN":"但就算我們是同個時期進到設施，吃同樣的飯，讀一樣的書……也不代表我們就是一家人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저는 단 한 번도 그 남자를 가족이라고 생각해본 적 없으니까요.","JPN":"私は一度もあの男を家族と思ったことがないのですから。","ENG":"I have never thought of \\"that man\\" as family.","TWN":"我從未將那男的視為家人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"또한 예하께서 말씀하신대로 현재 제 소속은 심의회가 아닙니다.","JPN":"また、猊下のおしゃったとおり現在私の所属は審議会ではありません。","ENG":"Furthermore, as you have also mentioned, I am not a member of the Investigation Council anymore.","TWN":"此外，正如同主教所言，我現在已經不隸屬於議會，"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그러니, 유감스럽게도 저는 예하의 지시를 따를 이유가 없죠.","JPN":"ですから、残念ながら猊下の指示に従う理由がないのです。","ENG":"Therefore, I have no reason to follow your orders, your Eminence.","TWN":"自然也就沒有理由要遵守主教的指示，很抱歉。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"한 번만 다시 생각해 보게. 비블리데.","JPN":"もう一度考え直してくれ。ビブリデ。","ENG":"Please reconsider, Biblide.","TWN":"布莉黛，你再考慮考慮吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아니요. 한 번 더 노골적으로 말씀드리겠습니다.","JPN":"いいえ。もう一度率直にお話いたしましょう。","ENG":"No. I will be more blunt this time.","TWN":"不需要，我再說得明白點，"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저는 앞으로 두 번 다시 그 남자와 엮이고 싶지 않습니다.","JPN":"私は二度とあの男と関わりたくありません。","ENG":"I do not wish to have anything to do with \\"that man\\".","TWN":"我再也不想和那男的有任何牽扯。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하께서 저 역시 자식처럼 여기신다면…… 제 무례를 헤아려 주십시오.","JPN":"猊下が私を娘のように思ってくださるのでしたら……無礼をお許しください。","ENG":"And if you also think of me as your family... Please understand my rudeness.","TWN":"若主教也將我視如己出……那就請原諒我的無禮。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};